import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return empty set when given empty set");
  it.todo("should kill a single live cell with no neighbors (underpopulation)");
  it.todo("should kill live cells with only one neighbor (underpopulation)");
  it.todo("should keep alive a live cell with two live neighbors (survival)");
  it.todo("should keep alive a live cell with three live neighbors (survival)");
  it.todo("should kill a live cell with more than three live neighbors (overpopulation)");
  it.todo("should bring to life a dead cell with exactly three live neighbors (reproduction)");
  it.todo("should preserve a block still life unchanged");
  it.todo("should oscillate a vertical blinker into a horizontal blinker");
  it.todo("should support negative coordinates");
});
